var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"AEGIS 8 PBLIT SECURITY SEQUENCE <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR <color=#ffd34c>ALPHA CONFIRMED</color>      \\nCCN No. AS001L0059-01: <color=#ffd34c>【기록-015】 적성 평가</color>      ","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR <color=#ffd34c>ALPHA CONFIRMED</color>      \\nCCN No. AS001L0059-01：<color=#ffd34c>【記録-015】 適性評価</color>      ","ENG":"AEGIS 8 PBLIT SECURITY SEQUENCE <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR <color=#ffd34c>ALPHA CONFIRMED</color>      \\nCCN No. AS001L0059-01: <color=#ffd34c>【Record-015】 Aptitude Evaluation</color>      ","TWN":"AEGIS 8 PBLIT SECURITY SEQUENCE <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR <color=#ffd34c>ALPHA CONFIRMED</color>      \\nCCN No. AS001L0059-01: <color=#ffd34c>【記錄-015】 能力評價</color>","THA":"กระบวนการตรวจสอบประวัติเพื่อความปลอดภัย AEGIS 8 PBLIT: <color=#ffd34c>เปิดทำงาน</color>     \\nADC แฟกเตอร์: <color=#ffd34c>ยืนยันในระดับอัลฟ่า</color>     \\nCCN หมายเลข AS001L0059-01: <color=#ffd34c>[บันทึก-015] การประเมินความสามารถ</color>","VTN":"TRÌNH TỰ AN NINH AEGIS 8 PBLIT: <color=#ffd34c>ĐÃ KÍCH HOẠT</color>     \\nTHÔNG SỐ ADC: <color=#ffd34c>XÁC NHẬN ALPHA </color>     \\nCCN Số AS001L0059-01: <color=#ffd34c>[Hồ Sơ-015] Hội Thảo Đánh Giá</color>","SCN":"AEGIS 8 PBLIT安全序列: <color=#ffd34c>激活</color>\\nADC 因素: <color=#ffd34c>阿尔法确认</color>      \\nCCN No. AS001L0059-01: <color=#ffd34c>【记录-015】 能力评价</color>      ","DEU":"AEGIS 8 PBLIT-SICHERHEITSSEQUENZ: <color=#ffd34c>AKTIVIERT</color>     \\nADC-FAKTOR: <color=#ffd34c>ALPHA BESTÄTIGT</color>     \\nCCN-Nr. AS001L0059-01: <color=#ffd34c>【Aufzeichnung-015】 Eignungsbewertung</color>      ","FRA":"AEGIS 8 PROTOCOLE DE SÉCURITÉ PBLIT\xA0: <color=#ffd34c>ACTIVÉ</color>     \\nFACTEUR CAD\xA0: <color=#ffd34c>ALPHA CONFIRMÉ</color>     \\nCCN No. AS001L0059-01\xA0: <color=#ffd34c>【Rapport\xA0-015】 Bilan de compétences</color>      "},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"......그러니까 당신이 진짜 사장님이라는 거군요.","JPN":"……あなたが本当の社長なんですね。","ENG":"So you're the real CEO of this company?","TWN":"……所以，您才是真正的老闆吧。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래. 별로 놀라지 않는군. 의외인데?","JPN":"ああ、あまり驚かないんだな？","ENG":"Yes. You don't seem too surprised. That's unexpected.","TWN":"是的，妳不怎麼驚訝呢。明明很意外吧？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그야 처음부터 반자율형 원격조작 머신이라고 소개 받았으니까요.","JPN":"初めから、半自律型の遠隔操作マシーンだと紹介されていたので。","ENG":"Well, I was already told that you are a semi-autonomous remote controlled machine.","TWN":"那是因為從一開始，就聽到您介紹說，這是半自動型遠端操作機。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그렇지 않고서야 그 지독......","JPN":"でなければ、あのキツイ……","ENG":"If not, that nasty...","TWN":"不然的話，那位壞心的……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"아니, 깐깐한 부사장님이 로봇을 상사로 모실 리가 없죠.","JPN":"いえ、気難しい副社長が、ロボットを上司として認めるわけがありません。","ENG":"Ahem, our particular Vice President would never accept a robot as her superior.","TWN":"不，是倔強的副總不可能會把機器人當成上司吧。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"배후에 누가 있을 거라는 추측 정도는 충분히 할 수 있습니다.","JPN":"背後に誰かがいるということくらいは、十分察することができます。","ENG":"I speculate that someone's controlling the robot with a remote.","TWN":"這樣就能推測出背後有誰在主使了。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"눈치가 좋군.","JPN":"勘がいいな。","ENG":"You're good.","TWN":"觀察得不錯。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......버릇은 없지만요.","JPN":"……生意気ですが。","ENG":"Although a bit rude.","TWN":"……很沒禮貌就是了。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"하하, 부사장님께는 내숭을 떨 필요가 없으니까요.","JPN":"はは、副社長の前では猫をかぶる必要がありませんから。","ENG":"Hah hah, it's because I don't have to be coy with you.","TWN":"哈哈，因為沒必要在副總面前裝乖啊。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"솔직한 모습을 보여드릴 만큼 존경하고 있다는 뜻으로 받아들여주시면 좋겠어요.","JPN":"ありのままの自分をお見せするほど、尊敬しているという意味です。","ENG":"Just think of it as a sign of respect I'm expressing towards you by being honest.","TWN":"我尊敬副總到會在副總面前展現出誠實的一面，希望您能理解成這個意思。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"나도 솔직하게 말해 주는 건데,","JPN":"私も正直に言いますけど、","ENG":"I'm being honest here as well.","TWN":"那我也就誠實地說吧。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"자네의 존경이 전혀 기쁘지가 않군.","JPN":"尊敬されても、まったく嬉しくないです。","ENG":"But your respect isn't very welcoming.","TWN":"對於妳的尊敬，我一點都不感到高興。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"대체 우리 회사에는 왜 이런 뒤틀린 사람들만 모여드는 건지......","JPN":"何でうちの会社には、こういうひねくれものばかり集まるのか……","ENG":"How come our company is always filled with twisted people?","TWN":"我們公司到底為什麼，只會聚集一些性格扭曲的人啊……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하아......","JPN":"はあ……","ENG":"*Sigh*","TWN":"唉……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그야 사장부터 아주 단단히 뒤틀려 있으니 그런 게 아니겠나?","JPN":"そりゃあ、社長がひねくれものだからな！","ENG":"Well, it's probably because the CEO is a twisted person to begin with. No?","TWN":"因為從老闆開始，就已經扭曲得很徹底了不是嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_LONG","text":{"KOREA":"경고! 경고! 강력한 감정적 충격이 감지되었습니다!","JPN":"警告！警告！感情のこもった、強力な衝撃が感知されました！","ENG":"Warning! Warning! A powerful emotional shock was detected!","TWN":"警告！ 警告！偵測到強力的情緒衝擊！"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_LONG","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};